        perfetto::WriteIntoTracedValueWithFallback(dict.AddItem("local_addr"), in_local_addr, "<value of type const absl::optional<::net::IPEndPoint>&>");
        perfetto::WriteIntoTracedValueWithFallback(dict.AddItem("peer_addr"), in_peer_addr, "<value of type const absl::optional<::net::IPEndPoint>&>");
