bool StructTraits<::blink::mojom::blink::DirectSocketOptions::DataView, ::blink::mojom::blink::DirectSocketOptionsPtr>::Read(
    ::blink::mojom::blink::DirectSocketOptions::DataView input, ::blink::mojom::blink::DirectSocketOptionsPtr* output)
{
    bool success = true;
    ::blink::mojom::blink::DirectSocketOptionsPtr result(::blink::mojom::blink::DirectSocketOptions::New());

    if (success && !input.ReadLocalHostname(&result->local_hostname))
        success = false;
    if (success)
        result->local_port = input.local_port();
    if (success && !input.ReadRemoteHostname(&result->remote_hostname))
        success = false;
    if (success)
        result->remote_port = input.remote_port();
    if (success)
        result->send_buffer_size = input.send_buffer_size();
    if (success)
        result->receive_buffer_size = input.receive_buffer_size();
    if (success)
        result->no_delay = input.no_delay();
    if (success && !input.ReadKeepAliveOptions(&result->keep_alive_options))
        success = false;
    *output = std::move(result);
    return success;
}

